  <rect x="360" y="62" width="320" height="42" rx="6" fill="#18181b" stroke="#3f3f46"/>
  <text x="520" y="88" fill="#e4e4e7" font-family="sans-serif" font-size="13" font-weight="700" text-anchor="middle">143 Có Phán Quyết Nội Dung (8,8%)</text>
