<div class="id">
<svg viewBox="0 0 700 400" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
  <text x="20" y="28" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">Arbitrase Konsumen Kripto: 143 Putusan dari 1.617 Kasus yang Diajukan — Nasabah Hanya Menang 12</text>
  <text x="20" y="48" fill="#71717a" font-size="12" font-family="sans-serif">Analisis Stack &amp; Story terhadap data AAA/JAMS yang diungkapkan berdasarkan undang-undang California</text>
  <rect x="20" y="62" width="320" height="42" rx="6" fill="#18181b" stroke="#3f3f46"/>
  <text x="180" y="88" fill="#e4e4e7" font-family="sans-serif" font-size="13" font-weight="700" text-anchor="middle">1.617 Kasus Diajukan</text>
