  <rect x="20" y="112" width="320" height="42" rx="6" fill="#0f1f18" stroke="#15803d"/>
  <text x="180" y="138" fill="#bbf7d0" font-family="sans-serif" font-size="13" text-anchor="middle">Nasabah Menang 12 (8%)</text>
  <rect x="360" y="112" width="320" height="42" rx="6" fill="#1f1315" stroke="#7f1d1d"/>
  <text x="520" y="138" fill="#fecaca" font-family="sans-serif" font-size="13" text-anchor="middle">Perusahaan Menang 113 (79%)</text>
