  <text x="180" y="188" fill="#d4d4d8" font-family="sans-serif" font-size="13" text-anchor="middle">Putusan Terbagi 1</text>
  <rect x="360" y="162" width="320" height="42" rx="6" fill="#18181b" stroke="#3f3f46"/>
  <text x="520" y="188" fill="#d4d4d8" font-family="sans-serif" font-size="13" text-anchor="middle">Tidak Ada Pemenang Tercatat 17</text>
