<div class="pl">
<svg viewBox="0 0 700 400" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
  <text x="20" y="28" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">Arbitraż Konsumencki w Kryptowalutach: 143 Orzeczenia z 1617 Złożonych Spraw — Klienci Wygrali Tylko 12</text>
  <text x="20" y="48" fill="#71717a" font-size="12" font-family="sans-serif">Analiza Stack &amp; Story danych AAA/JAMS ujawnionych na mocy prawa Kalifornii</text>
  <rect x="20" y="62" width="320" height="42" rx="6" fill="#18181b" stroke="#3f3f46"/>
